import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { 
  Cpu, 
  LayoutDashboard, 
  TrendingUp, 
  LogOut, 
  ShieldCheck,
  Terminal,
  User
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const { theme } = useTheme();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  const styles = {
    // 🎯 FIX: Uses the same width logic as your login card for perfect alignment
    nav: { 
      position: 'sticky', 
      top: '15px', 
      zIndex: 100, 
      margin: '0 auto',
      width: '95%', 
      maxWidth: '1200px',
      backgroundColor: 'var(--card-bg)', 
      borderRadius: '20px',
      padding: '0.6rem 1.5rem',
      border: '1px solid var(--border-color)', 
      boxShadow: 'var(--shadow-soft)',
      backdropFilter: 'blur(12px)',
      display: 'flex',
      justifyContent: 'center'
    },
    container: { 
      display: 'flex', 
      justifyContent: 'space-between', 
      alignItems: 'center',
      width: '100%'
    },
    logo: { 
      fontSize: '1.2rem', 
      color: 'var(--text-main)', 
      textDecoration: 'none', 
      display: 'flex', 
      alignItems: 'center', 
      gap: '10px',
      fontWeight: 'bold',
      letterSpacing: '0.15em',
      textTransform: 'uppercase'
    },
    navLinks: { display: 'flex', alignItems: 'center', gap: '0.5rem' },
    
    // ⚡ Active Node Logic: Emerald highlight matching your theme.js
    link: (active) => ({
      textDecoration: 'none',
      fontWeight: '700',
      fontSize: '10px',
      padding: '0.5rem 1rem',
      borderRadius: '10px',
      display: 'flex', 
      alignItems: 'center', 
      gap: '8px',
      transition: 'all 0.3s ease',
      backgroundColor: active ? 'var(--accent-muted)' : 'transparent',
      color: active ? 'var(--primary-accent)' : 'var(--text-muted)',
      border: active ? '1px solid var(--primary-accent)' : '1px solid transparent',
      textTransform: 'uppercase',
      letterSpacing: '0.1em'
    }),
    
    logoutBtn: { 
      backgroundColor: 'rgba(239, 68, 68, 0.1)', 
      color: '#ef4444', 
      border: '1px solid rgba(239, 68, 68, 0.2)',
      padding: '0.5rem 0.8rem', 
      borderRadius: '10px', 
      cursor: 'pointer', 
      display: 'flex', 
      alignItems: 'center',
      transition: 'all 0.2s ease',
      marginLeft: '0.5rem'
    }
  };

  return (
    <nav style={styles.nav} className="reveal-data">
      <div style={styles.container}>
        {/* Brand Identity */}
        <Link to="/dashboard" style={styles.logo}>
          <div className="p-1.5 bg-emerald-500/10 rounded-lg">
            <Cpu size={20} className="text-emerald-500" />
          </div>
          <span className="hidden sm:inline">Finify AI</span>
        </Link>

        <div style={styles.navLinks}>
          {user ? (
            <>
              <Link to="/dashboard" style={styles.link(isActive('/dashboard'))}>
                <LayoutDashboard size={14} /> Dashboard
              </Link>
              <Link to="/generate" style={styles.link(isActive('/generate'))}>
                <TrendingUp size={14} /> Strategy
              </Link>
              <Link to="/profile" style={styles.link(isActive('/profile'))}>
                <User size={14} /> Node
              </Link>
              <button onClick={handleLogout} style={styles.logoutBtn} title="Terminate Session">
                <LogOut size={14} />
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={styles.link(isActive('/login'))}>
                <Terminal size={14} /> Access
              </Link>
              <Link 
                to="/register" 
                style={{
                  ...styles.link(true), 
                  backgroundColor: 'var(--primary-accent)', 
                  color: '#000',
                  border: 'none'
                }}
              >
                <ShieldCheck size={14} /> Initialize
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
